import React, { useState, useEffect } from "react";
import { getCategories, createCategory, deleteCategory } from "../services/CategoryService";

const CategoryManager = ({ onCategoriesChange }) => {
  const [categories, setCategories] = useState([]);
  const [newTitle, setNewTitle] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const data = await getCategories();
      setCategories(data);
      if(onCategoriesChange) onCategoriesChange(data);
    } catch (err) {
      setError("Error al cargar categorías.");
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    if (!newTitle.trim()) return;

    try {
      const cat = await createCategory({ title: newTitle });
      const updated = [...categories, cat];
      setCategories(updated);
      setNewTitle("");
      setError("");
      if(onCategoriesChange) onCategoriesChange(updated);
    } catch (err) {
      setError("Error al crear categoría. Asegúrate de tener permisos.");
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("¿Seguro que quieres borrar esta categoría?")) return;
    try {
      await deleteCategory(id);
      const updated = categories.filter((c) => c.id !== id);
      setCategories(updated);
      setError("");
      if(onCategoriesChange) onCategoriesChange(updated);
    } catch (err) {
      setError("Error al borrar categoría. Podría estar en uso por alguna tarea.");
    }
  };

  return (
    <div style={{ marginTop: "30px", padding: "20px", backgroundColor: "#fff3cd", border: "1px solid #ffeeba", borderRadius: "8px" }}>
      <h3 style={{ marginTop: 0, color: "#856404" }}>🛠️ Panel de Administración (Gestión de Categorías)</h3>
      <p style={{ fontSize: "14px", color: "#666" }}>Esta zona es solo visible para usuarios con rol GESTOR o ADMIN.</p>

      {error && <p style={{ color: "red", fontSize: "14px", fontWeight: "bold" }}>⚠️ {error}</p>}

      <form onSubmit={handleAdd} style={{ display: "flex", gap: "10px", marginBottom: "15px" }}>
        <input 
          type="text" 
          placeholder="Nueva categoría..." 
          value={newTitle} 
          onChange={(e) => setNewTitle(e.target.value)} 
          style={{ flex: 1, padding: "8px" }}
        />
        <button type="submit" style={{ padding: "8px 15px", backgroundColor: "#28a745", color: "white", border: "none", borderRadius: "4px", cursor: "pointer", fontWeight:"bold" }}>
          Añadir Categoría
        </button>
      </form>

      <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
        {categories.length === 0 && <li style={{ fontSize:"13px", color:"#888" }}>No hay categorías. Crea una.</li>}
        {categories.map((cat) => (
          <li key={cat.id} style={{ display: "flex", justifyContent: "space-between", alignItems:"center", padding: "8px", borderBottom: "1px solid #f5c6cb" }}>
            <span style={{ color: "#555", fontWeight: "500" }}>{cat.title}</span>
            <button onClick={() => handleDelete(cat.id)} style={{ backgroundColor: "#dc3545", color: "white", border: "none", borderRadius: "4px", padding: "6px 10px", cursor: "pointer", fontSize: "12px" }}>
              Borrar
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default CategoryManager;
